    #[test]
    fn test_audience_verification() {
        let verifier = JwtVerifier::new()
            .add_hmac_key(test_secret(), Algorithm::HS256, None)
            .set_required_audiences(vec!["my-app".to_string()]);

        // Token with correct audience
        let valid_token = create_test_token(
            "user-1",
            test_secret(),
            Algorithm::HS256,
            3600,
            None,
            None,
            None,
            None,
            Some(vec!["my-app".to_string()]),
        )
        .unwrap();

        assert!(verifier.verify_token(&valid_token).is_ok());

        // Token with wrong audience
        let invalid_token = create_test_token(
            "user-1",
            test_secret(),
            Algorithm::HS256,
            3600,
            None,
            None,
            None,
            None,
            Some(vec!["other-app".to_string()]),
        )
        .unwrap();

        assert!(verifier.verify_token(&invalid_token).is_err());
    }
